query:
{
  dbInstances(
    where: {
      cyscaleEngineIsOutdated: { eq: true }
      NOT: {
        OR: [
          { cloudProvider: { eq: "aws" }, engine: { eq: "mysql" }, engineVersion_MATCHES: "^5\\.7(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mysql" }, engineVersion_MATCHES: "^8\\.0(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mysql" }, engineVersion_MATCHES: "^8\\.4(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mariadb" }, engineVersion_MATCHES: "^10\\.5(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mariadb" }, engineVersion_MATCHES: "^10\\.6(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mariadb" }, engineVersion_MATCHES: "^10\\.11(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mariadb" }, engineVersion_MATCHES: "^11\\.4(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "mariadb" }, engineVersion_MATCHES: "^11\\.8(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^11(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^12(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^13(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^14(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^15(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^16(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^17(\\.|$)" }
          { cloudProvider: { eq: "aws" }, engine: { eq: "postgres" }, engineVersion_MATCHES: "^18(\\.|$)" }
          { cloudProvider: { eq: "alibaba" }, engine: { eq: "mysql" }, engineVersion_MATCHES: "^5\\.7(\\.|$)" }
          { cloudProvider: { eq: "alibaba" }, engine: { eq: "mysql" }, engineVersion_MATCHES: "^8\\.0(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engine
    engineVersion
    cyscaleEngineIsOutdated
  }
}
